import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {

    public static void main(String[] args) throws IOException {
        // Simulated user input from a form or request parameter
        String userInput = "<script>alert('XSS attack!')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Write sanitized content to an HTML file
        File file = new File("response.html");
        FileWriter writer = new FileWriter(file);

        writer.write("<html>");
        writer.write("<body>");
        writer.write("<h1>Welcome, " + sanitizedInput + "</h1>"); // Safe code - sanitized user input
        writer.write("</body>");
        writer.write("</html>");

        writer.close();

        System.out.println("HTML response generated successfully.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
